entry.content:
动态编译 动态编译的应用场景 可以做一个浏览器端编写java代码，上传服务器编译和运行的在线评测系统 服务器动态加载某些类文件进行编译 动态编译的两种做法 通过Runtime调用javac，启动新的进程去操作 12Runtime run = Runtime.getRuntime();Process process = run.exe("javac -cp d:/myjava/a.java"); 通过JavaComplier动态编译 12345678910JavaCompiler compiler = ToolProvider.getSystemJavaCompiler(); int result = compiler.run(null,null,null,"/home/zephon/桌面/a.java"); System.out.println(result==0?"编译成功":"编译失败"); //对于字符串，可通过IO流操作，将字符串存储成一个临时文件，然后调用动态编译方法 String str = "public class a&#123;
" + "	public static void main(String[] args)&#123;
" + "		System.out.println("hello");
" + "	&#125;
" + "&#125;"; 动态运行编译好的类 通过Runtime.getRuntime()启动新的进程运行 12Runtime run = Runtime.getRuntime();Process pro = run.exec("java -cp ./temp temp/com/Hello") 通过反射运行编译好的类 1234567URL[] urls = new URL[]&#123;new URL("file:")&#125;; System.out.println(urls[0]); URLClassLoader loader = new URLClassLoader(urls); Class c = loader.loadClass("Hello"); //调用加载类的main方法 Method m = c.getMethod("main",String[].class); m.invoke(null,(Object)new String[]&#123;"aa","bb"&#125;); 动态编译代码字符串12345678910111213141516171819202122232425262728293031323334353637383940// 1.创建需要动态编译的代码字符串 String nr = "
"; //回车 String source = "package temp.com; " + nr + " public class Hello&#123;" + nr + " public static void main (String[] args)&#123;" + nr + " System.out.println("HelloWorld! 1");" + nr + " &#125;" + nr + " &#125;"; // 2.将欲动态编译的代码写入文件中 1.创建临时目录 2.写入临时文件目录 File dir = new File(System.getProperty("user.dir") + "/temp"); //临时目录 // 如果 	emp 不存在 就创建 if (!dir.exists()) &#123; dir.mkdir(); &#125; FileWriter writer = new FileWriter(new File(dir,"Hello.java")); writer.write(source); writer.flush(); writer.close(); // 3.取得当前系统的编译器 JavaCompiler javaCompiler = ToolProvider.getSystemJavaCompiler(); // 4.获取一个文件管理器 StandardJavaFileManager javaFileManager = javaCompiler.getStandardFileManager(null, null, null); // 5.文件管理器根与文件连接起来 Iterable it = javaFileManager.getJavaFileObjects(new File(dir,"Hello.java")); // 6.创建编译任务 JavaCompiler.CompilationTask task = javaCompiler.getTask(null, javaFileManager, null, Arrays.asList("-d", "./temp"), null, it); // 7.执行编译 task.call(); javaFileManager.close(); // 8.运行程序 Runtime run = Runtime.getRuntime(); Process process = run.exec("java -cp ./temp temp/com/Hello"); InputStream in = process.getInputStream(); BufferedReader reader = new BufferedReader(new InputStreamReader(in)); String info = ""; while ((info = reader.readLine()) != null) &#123; System.out.println(info); &#125; 脚本引擎执行javascrpit代码12345678910111213141516171819//获得脚本引擎对象ScriptEngineManager sem = new ScriptEngineManager(); ScriptEngine engine = sem.getEngineByName("nashorn"); //定义变量,会存储到引擎上下文中 engine.put("msg","hello world"); String str ="var user = &#123;name:'张三',age:20&#125;;"; //执行脚本 engine.eval(str); System.out.println(engine.get("msg")); //定义函数 engine.eval("function add(a,b)&#123;var sum = a+b;return sum;&#125;"); //执行函数 Invocable jsInvoke = (Invocable)engine; Object result = jsInvoke.invokeFunction("add",new Object[]&#123;2,4&#125;); System.out.println(result);
